# AutoDev Layer 6 Self-Contained Deploy
# All file contents embedded as base64 - just run this one script

$ErrorActionPreference = "Continue"
[Console]::OutputEncoding = [System.Text.Encoding]::UTF8
$target = "C:\Users\Administrator"

echo "[Layer6-Deploy] Starting..."

$autodev_evolve_b64 += ""
$autodev_evolve_b64 += ""
$autodev_evolve_b64 += ""
$autodev_evolve_b64 += ""
$autodev_evolve_b64 += ""

$autodev_brain_b64 += ""
$autodev_brain_b64 += ""
$autodev_brain_b64 += ""
$autodev_brain_b64 += ""
$autodev_brain_b64 += ""
$autodev_brain_b64 += ""
$autodev_brain_b64 += ""
$autodev_brain_b64 += ""
$autodev_brain_b64 += ""

$autodev_scheduler_b64 += ""


# Function to decode and write
function WriteB64File($b64, $path) {
    $bytes = [Convert]::FromBase64String($b64)
    [IO.File]::WriteAllBytes($path, $bytes)
    $sz = (Get-Item $path).Length
    echo "  Written: $path ($sz bytes)"
}

# 1. Deploy autodev-evolve.ps1 (NEW - Layer 6 core)
echo "[1/4] Deploying autodev-evolve.ps1..."
WriteB64File $autodev_evolve_b64 "$target\autodev-evolve.ps1"

# 2. Deploy autodev-brain.ps1 (v3.1 strategy-aware)
echo "[2/4] Deploying autodev-brain.ps1..."
WriteB64File $autodev_brain_b64 "$target\autodev-brain.ps1"

# 3. Deploy autodev-scheduler.ps1 (8-step with Layer 6)
echo "[3/4] Deploying autodev-scheduler.ps1..."
WriteB64File $autodev_scheduler_b64 "$target\autodev-scheduler.ps1"

# 4. Create skills directory
echo "[4/4] Creating skills directory..."
if (-not (Test-Path "$target\projects\skills")) {
    New-Item -ItemType Directory -Path "$target\projects\skills" -Force | Out-Null
}

echo ""
echo "===== VERIFICATION ====="
$allOk = $true

foreach ($f in @("autodev-evolve.ps1", "autodev-brain.ps1", "autodev-scheduler.ps1")) {
    $p = "$target\$f"
    if (Test-Path $p) {
        $sz = (Get-Item $p).Length
        echo "  $f : $sz bytes OK"
    } else {
        echo "  $f : MISSING"
        $allOk = $false
    }
}

if (Test-Path "$target\projects\skills") {
    echo "  skills dir: EXISTS"
} else {
    echo "  skills dir: MISSING"
    $allOk = $false
}

$brainCheck = Get-Content "$target\autodev-brain.ps1" -Raw
if ($brainCheck -match "STRATEGY_FILE") {
    echo "  brain v3.1 strategy-aware: YES"
} else {
    echo "  brain v3.1 strategy-aware: NO"
    $allOk = $false
}

$schedCheck = Get-Content "$target\autodev-scheduler.ps1" -Raw
if ($schedCheck -match "autodev-evolve") {
    echo "  scheduler Layer 6 step: YES"
} else {
    echo "  scheduler Layer 6 step: NO"
    $allOk = $false
}

echo ""
if ($allOk) {
    echo "ALL VERIFIED OK - Layer 6 Evolution Engine deployed!"
    echo ""
    echo "Layer 6 features:"
    echo "  - autodev-evolve.ps1: Analyzes history, crystallizes skills, adapts strategy"
    echo "  - Brain v3.1: Strategy-aware evaluation (reads strategy.json + skills)"
    echo "  - Scheduler v2: 8-step pipeline (Finance->5Monitors->Brain->Deploy->EVOLVE)"
    echo "  - skills/ directory: Reusable skill templates"
    echo "  - strategy.json: Adaptive parameters (source weights, avoid patterns, etc.)"
} else {
    echo "SOME CHECKS FAILED - review above"
}

echo ""
echo "[Layer6-Deploy] COMPLETE"
pause
